import React, { useState } from 'react';
import { useMutation, useQueryClient } from '@tanstack/react-query';
import { Download, Trash2, User } from 'lucide-react';
import { reportsApi } from '../api/reports';
import { exportApi } from '../api/export';
import FileImport from '../components/FileImport';
import ImportedDataTable from '../components/ImportedDataTable';
import Card from '../components/Card';
import { useClient } from '../contexts/ClientContext';

const BusinessData: React.FC = () => {
  const { selectedClient } = useClient();
  const [formData, setFormData] = useState({
    report_date: '',
    month_label: '',
    registered_onboarded: '',
    linked_accounts: '',
    total_advance_applications: '',
    total_advance_applicants: '',
    total_micro_financing_applications: '',
    total_micro_financing_applicants: '',
    total_personal_finance_application: '',
    total_personal_finance_applicants: '',
    totalBnplApplication: '',
    totalBnplApplicants: '',
    notes: '',
  });

  const queryClient = useQueryClient();

  const createReportMutation = useMutation({
    mutationFn: reportsApi.createReport,
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['reports'] });
      queryClient.invalidateQueries({ queryKey: ['stats'] });
      clearForm();
    },
  });

  const clearAllMutation = useMutation({
    mutationFn: reportsApi.clearAll,
    onSuccess: () => {
      queryClient.invalidateQueries();
      window.location.reload(); // Force full refresh to update all tables
    },
  });

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    
    if (!formData.report_date) {
      alert('Date is required');
      return;
    }

    if (!selectedClient) {
      alert('Please select a client first');
      return;
    }

    const data: Record<string, any> = {};
    
    // Convert numeric fields
    const numericFields = [
      'registered_onboarded',
      'linked_accounts', 
      'total_advance_applications',
      'total_advance_applicants',
      'total_micro_financing_applications',
      'total_micro_financing_applicants',
      'total_personal_finance_application',
      'total_personal_finance_applicants',
      'totalBnplApplication',
      'totalBnplApplicants',
    ];

    numericFields.forEach(field => {
      const value = formData[field as keyof typeof formData];
      if (value) {
        const numValue = Number(value);
        if (!isNaN(numValue)) {
          data[field] = numValue;
        }
      }
    });

    if (formData.notes) {
      data.notes = formData.notes;
    }

    createReportMutation.mutate({
      report_date: formData.report_date,
      month_label: formData.month_label || undefined,
      data,
      clientId: selectedClient.id,
    });
  };

  const clearForm = () => {
    setFormData({
      report_date: '',
      month_label: '',
      registered_onboarded: '',
      linked_accounts: '',
      total_advance_applications: '',
      total_advance_applicants: '',
      total_micro_financing_applications: '',
      total_micro_financing_applicants: '',
      total_personal_finance_application: '',
      total_personal_finance_applicants: '',
      totalBnplApplication: '',
      totalBnplApplicants: '',
      notes: '',
    });
  };

  const handleClearAll = () => {
    const confirmed = window.confirm(
      'Are you sure you want to clear all data? This action cannot be undone.'
    );
    if (confirmed) {
      clearAllMutation.mutate();
    }
  };

  const handleInputChange = (field: string, value: string) => {
    setFormData(prev => ({ ...prev, [field]: value }));
  };

  return (
    <div className="max-w-full mx-auto px-4 sm:px-6 lg:px-32 py-8">
      {!selectedClient ? (
        <Card>
          <div className="text-center py-12">
            <div className="w-16 h-16 mx-auto mb-4 bg-gray-100 rounded-full flex items-center justify-center">
              <User className="w-8 h-8 text-gray-400" />
            </div>
            <h3 className="text-lg font-medium text-gray-900 mb-2">
              Client Selection Required
            </h3>
            <p className="text-gray-600">
              Please select a client from the home page to access business data management features.
            </p>
          </div>
        </Card>
      ) : (
        <>
          <h1 className="text-2xl font-bold text-gray-900 mb-2">
            Business Data Management - {selectedClient.name}
          </h1>
          <p className="text-gray-600 mb-8">
            Import, manage, and export business data for {selectedClient.name}
          </p>

          {/* Import Section */}
          <div className="mb-8">
            <FileImport />
          </div>

          {/* Imported Data Table */}
          <div className="mb-8">
        <ImportedDataTable />
      </div>

      {/* Manual Entry Form */}
      <Card className="mb-8" style={{maxWidth: '100%'}}>
        <h3 className="text-lg font-semibold text-gray-900 mb-6">Manual Data Entry</h3>
        <form onSubmit={handleSubmit} className="space-y-6">
          {/* Date and Month */}
          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            <div>
              <label className="block text-sm font-medium text-gray-700 mb-1">
                Date <span className="text-red-500">*</span>
              </label>
              <input
                type="date"
                value={formData.report_date}
                onChange={(e) => handleInputChange('report_date', e.target.value)}
                className="w-full border border-gray-300 rounded-md px-3 py-2 focus:outline-none focus:ring-2 focus:ring-primary-500 focus:border-primary-500"
                required
              />
            </div>
            <div>
              <label className="block text-sm font-medium text-gray-700 mb-1">
                Month Label
              </label>
              <input
                type="text"
                value={formData.month_label}
                onChange={(e) => handleInputChange('month_label', e.target.value)}
                placeholder="e.g., September 2025"
                className="w-full border border-gray-300 rounded-md px-3 py-2 focus:outline-none focus:ring-2 focus:ring-primary-500 focus:border-primary-500"
              />
            </div>
          </div>

          {/* Metrics Grid */}
          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            <div>
              <label className="block text-sm font-medium text-gray-700 mb-1">
                Registered Onboarded
              </label>
              <input
                type="number"
                value={formData.registered_onboarded}
                onChange={(e) => handleInputChange('registered_onboarded', e.target.value)}
                className="w-full border border-gray-300 rounded-md px-3 py-2 focus:outline-none focus:ring-2 focus:ring-primary-500 focus:border-primary-500"
              />
            </div>
            <div>
              <label className="block text-sm font-medium text-gray-700 mb-1">
                Linked Accounts
              </label>
              <input
                type="number"
                value={formData.linked_accounts}
                onChange={(e) => handleInputChange('linked_accounts', e.target.value)}
                className="w-full border border-gray-300 rounded-md px-3 py-2 focus:outline-none focus:ring-2 focus:ring-primary-500 focus:border-primary-500"
              />
            </div>
            <div>
              <label className="block text-sm font-medium text-gray-700 mb-1">
                Total Advance Applications
              </label>
              <input
                type="number"
                value={formData.total_advance_applications}
                onChange={(e) => handleInputChange('total_advance_applications', e.target.value)}
                className="w-full border border-gray-300 rounded-md px-3 py-2 focus:outline-none focus:ring-2 focus:ring-primary-500 focus:border-primary-500"
              />
            </div>
            <div>
              <label className="block text-sm font-medium text-gray-700 mb-1">
                Total Advance Applicants
              </label>
              <input
                type="number"
                value={formData.total_advance_applicants}
                onChange={(e) => handleInputChange('total_advance_applicants', e.target.value)}
                className="w-full border border-gray-300 rounded-md px-3 py-2 focus:outline-none focus:ring-2 focus:ring-primary-500 focus:border-primary-500"
              />
            </div>
            <div>
              <label className="block text-sm font-medium text-gray-700 mb-1">
                Total Micro Financing Applications
              </label>
              <input
                type="number"
                value={formData.total_micro_financing_applications}
                onChange={(e) => handleInputChange('total_micro_financing_applications', e.target.value)}
                className="w-full border border-gray-300 rounded-md px-3 py-2 focus:outline-none focus:ring-2 focus:ring-primary-500 focus:border-primary-500"
              />
            </div>
            <div>
              <label className="block text-sm font-medium text-gray-700 mb-1">
                Total Micro Financing Applicants
              </label>
              <input
                type="number"
                value={formData.total_micro_financing_applicants}
                onChange={(e) => handleInputChange('total_micro_financing_applicants', e.target.value)}
                className="w-full border border-gray-300 rounded-md px-3 py-2 focus:outline-none focus:ring-2 focus:ring-primary-500 focus:border-primary-500"
              />
            </div>
            <div>
              <label className="block text-sm font-medium text-gray-700 mb-1">
                Total Personal Finance Application
              </label>
              <input
                type="number"
                value={formData.total_personal_finance_application}
                onChange={(e) => handleInputChange('total_personal_finance_application', e.target.value)}
                className="w-full border border-gray-300 rounded-md px-3 py-2 focus:outline-none focus:ring-2 focus:ring-primary-500 focus:border-primary-500"
              />
            </div>
            <div>
              <label className="block text-sm font-medium text-gray-700 mb-1">
                Total Personal Finance Applicants
              </label>
              <input
                type="number"
                value={formData.total_personal_finance_applicants}
                onChange={(e) => handleInputChange('total_personal_finance_applicants', e.target.value)}
                className="w-full border border-gray-300 rounded-md px-3 py-2 focus:outline-none focus:ring-2 focus:ring-primary-500 focus:border-primary-500"
              />
            </div>
            <div>
              <label className="block text-sm font-medium text-gray-700 mb-1">
                Total BNPL Applications
              </label>
              <input
                type="number"
                value={formData.totalBnplApplication}
                onChange={(e) => handleInputChange('totalBnplApplication', e.target.value)}
                className="w-full border border-gray-300 rounded-md px-3 py-2 focus:outline-none focus:ring-2 focus:ring-primary-500 focus:border-primary-500"
              />
            </div>
            <div>
              <label className="block text-sm font-medium text-gray-700 mb-1">
                Total BNPL Applicants
              </label>
              <input
                type="number"
                value={formData.totalBnplApplicants}
                onChange={(e) => handleInputChange('totalBnplApplicants', e.target.value)}
                className="w-full border border-gray-300 rounded-md px-3 py-2 focus:outline-none focus:ring-2 focus:ring-primary-500 focus:border-primary-500"
              />
            </div>
          </div>

          {/* Notes */}
          <div>
            <label className="block text-sm font-medium text-gray-700 mb-1">
              Notes
            </label>
            <textarea
              value={formData.notes}
              onChange={(e) => handleInputChange('notes', e.target.value)}
              rows={4}
              className="w-full border border-gray-300 rounded-md px-3 py-2 focus:outline-none focus:ring-2 focus:ring-primary-500 focus:border-primary-500"
              placeholder="Add any strategic insights or notes..."
            />
          </div>

          {/* Form Buttons */}
          <div className="flex space-x-4">
            <button
              type="submit"
              disabled={createReportMutation.isPending}
              className="btn-primary"
            >
              {createReportMutation.isPending ? 'Adding...' : 'Add Entry'}
            </button>
            <button
              type="button"
              onClick={clearForm}
              className="btn-secondary"
            >
              Clear Form
            </button>
          </div>
        </form>

        {createReportMutation.isError && (
          <div className="mt-4 p-3 bg-red-50 border border-red-200 rounded-md">
            <p className="text-red-800 text-sm">
              Error: {createReportMutation.error instanceof Error ? createReportMutation.error.message : 'Unknown error'}
            </p>
          </div>
        )}
      </Card>

      {/* Data Management */}
      <Card style={{maxWidth: '100%'}}>
        <h3 className="text-lg font-semibold text-gray-900 mb-4">Data Management</h3>
        <div className="flex flex-wrap gap-4">
          <button
            onClick={() => window.open('/labs', '_blank')}
            className="btn-secondary"
          >
            View All Data
          </button>
          
          <a
            href={exportApi.exportCsv()}
            className="btn-secondary inline-flex items-center"
          >
            <Download className="w-4 h-4 mr-2" />
            Export to CSV
          </a>
          
          <button
            onClick={handleClearAll}
            disabled={clearAllMutation.isPending}
            className="btn-danger inline-flex items-center"
          >
            <Trash2 className="w-4 h-4 mr-2" />
            {clearAllMutation.isPending ? 'Clearing...' : 'Clear All Data'}
          </button>
        </div>
      </Card>
        </>
      )}
    </div>
  );
};

export default BusinessData;
